text:
I'm developing a VS Code Copilot Chat extension and trying to invoke built-in Copilot tools such as copilot_editFile
or copilot_insertEdit
programmatically.
Read-only tools (e.g. copilot_readFile
) work fine, but any attempt to invoke edit/update tools fails. I've tried multiple variations (with/without cancellation tokens, different input formats, etc.), but all attempts to invoke edit/update tools fail (with sample code below).
Questions:
- Is it possible to invoke VS Code's built-in Copilot edit/update tools directly from a Copilot Chat extension?
- If yes, what's the correct way to do this?
- If not, is implementing custom tools the only viable alternative?
I'd greatly appreciate any guidance or examples. Implementing custom tools seems redundant, so I'd prefer to leverage VS Code's built-in capabilities if possible. Thanks!
// Test Approach 1: Standard token approach
console.log('🔍 Testing Approach 1: Standard token approach');
try {
console.log('🔍 Attempting copilot_createFile WITH token...');
const result1 = await vscode.lm.invokeTool('copilot_createFile', {
toolInvocationToken: toolInvocationToken,
input: {
filePath: filePath,
content: fileContent
}
}, token);
console.log('✅ Approach 1 SUCCESS: copilot_createFile with token worked!');
resultMessage += '✅ **Approach 1 (Standard token):** SUCCESS\n';
return {
content: [new vscode.LanguageModelTextPart(resultMessage + '\n🎉 File created successfully!')]
};
} catch (error1) {
const err1 = error1 instanceof Error ? error1 : new Error(String(error1));
console.log('❌ Approach 1 FAILED:', err1.message);
resultMessage += `❌ **Approach 1 (Standard token):** FAILED - ${err1.message}\n`;
// Test Approach 2: Fresh cancellation token
console.log('🔍 Testing Approach 2: Fresh cancellation token');
try {
const freshTokenSource = new vscode.CancellationTokenSource();
console.log('🔍 Attempting copilot_createFile with fresh cancellation token...');
const result2 = await vscode.lm.invokeTool('copilot_createFile', {
toolInvocationToken: toolInvocationToken,
input: {
filePath: filePath,
content: fileContent
}
}, freshTokenSource.token);
console.log('✅ Approach 2 SUCCESS: copilot_createFile with fresh token worked!');
resultMessage += '✅ **Approach 2 (Fresh cancellation token):** SUCCESS\n';
return {
content: [new vscode.LanguageModelTextPart(resultMessage + '\n🎉 File created successfully!')]
};
} catch (error2) {
const err2 = error2 instanceof Error ? error2 : new Error(String(error2));
console.log('❌ Approach 2 FAILED:', err2.message);
resultMessage += `❌ **Approach 2 (Fresh cancellation token):** FAILED - ${err2.message}\n`;
// Test Approach 3: No cancellation token
console.log('🔍 Testing Approach 3: No cancellation token');
try {
console.log('🔍 Attempting copilot_createFile without cancellation token...');
const result3 = await vscode.lm.invokeTool('copilot_createFile', {
toolInvocationToken: toolInvocationToken,
input: {
filePath: filePath,
content: fileContent
}
});
console.log('✅ Approach 3 SUCCESS: copilot_createFile without cancellation token worked!');
resultMessage += '✅ **Approach 3 (No cancellation token):** SUCCESS\n';
return {
content: [new vscode.LanguageModelTextPart(resultMessage + '\n🎉 File created successfully!')]
};
} catch (error3) {
const err3 = error3 instanceof Error ? error3 : new Error(String(error3));
console.log('❌ Approach 3 FAILED:', err3.message);
resultMessage += `❌ **Approach 3 (No cancellation token):** FAILED - ${err3.message}\n`;
// Test Approach 4: Undefined token
console.log('🔍 Testing Approach 4: Undefined token');
try {
console.log('🔍 Attempting copilot_createFile with undefined token...');
const result4 = await vscode.lm.invokeTool('copilot_createFile', {
toolInvocationToken: undefined,
input: {
filePath: filePath,
content: fileContent
}
}, token);
console.log('✅ Approach 4 SUCCESS: copilot_createFile with undefined token worked!');
resultMessage += '✅ **Approach 4 (Undefined token):** SUCCESS\n';
return {
content: [new vscode.LanguageModelTextPart(resultMessage + '\n🎉 File created successfully!')]
};
} catch (error4) {
const err4 = error4 instanceof Error ? error4 : new Error(String(error4));
console.log('❌ Approach 4 FAILED:', err4.message);
resultMessage += `❌ **Approach 4 (Undefined token):** FAILED - ${err4.message}\n`;
// Fallback: VS Code file system API
console.log('🔄 All copilot_createFile approaches failed, trying VS Code file system API...');
try {
const uri = vscode.Uri.file(filePath);
const content = new TextEncoder().encode(fileContent);
await vscode.workspace.fs.writeFile(uri, content);
console.log('✅ Fallback SUCCESS: VS Code file system API worked!');
resultMessage += '✅ **Fallback (VS Code FS API):** SUCCESS\n';
// Try to open the file
try {
const document = await vscode.workspace.openTextDocument(uri);
await vscode.window.showTextDocument(document);
console.log('✅ File opened in editor');
resultMessage += '✅ **File opened in editor:** SUCCESS\n';
} catch (openError) {
console.log('⚠️ Could not open file in editor:', openError);
resultMessage += '⚠️ **File opened in editor:** Could not open\n';
}
return {
content: [new vscode.LanguageModelTextPart(resultMessage + '\n🔧 File created using fallback VS Code API!')]
};
} catch (fallbackError) {
const fallbackErr = fallbackError instanceof Error ? fallbackError : new Error(String(fallbackError));
console.error('❌ Fallback FAILED:', fallbackErr.message);
resultMessage += `❌ **Fallback (VS Code FS API):** FAILED - ${fallbackErr.message}\n`;
return {
content: [new vscode.LanguageModelTextPart(resultMessage + '\n💥 All approaches failed!')]
};
}
}
}
}
}
